SELECT SUM(voters_turned_out) AS total_voters_turned_out
FROM voter_turnout
WHERE election_id = 0;

SELECT SUM(registered_voters) AS total_registered_voters
FROM elections
WHERE election_date = (SELECT MAX(election_date) FROM elections);

SELECT voter_id, registration_date, status
FROM voter_registration
WHERE county_id = 0 AND status = 'active';

SELECT voted
FROM voter_history
WHERE election_id = 0;
